INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(201,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What does AI stand for?','AI stands for Artificial Intelligence — the simulation of human intelligence by computer systems.',1),
(202,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'Which of the following is an example of Artificial Intelligence?','Siri and Google Assistant use AI to understand and respond to spoken questions.',1),
(203,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What type of AI exists today?','Only Narrow AI (designed for one specific task) exists today. General AI (human-level across all tasks) does not yet exist.',1),
(204,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'Which company developed the AI assistant called Siri?','Apple developed Siri, first introduced on the iPhone 4S in 2011.',1),
(205,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'What is machine learning?','Machine learning is a branch of AI where computers learn from data and improve their performance without being explicitly programmed.',1),
(206,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'Zipline uses drones to deliver medicine in Ghana. What technology makes this possible?','Zipline drones in Ghana use AI and autonomous flight technology to deliver blood and medicine to remote areas.',1),
(207,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'Which of the following is NOT an example of AI in everyday life?','A calculator performs fixed mathematical operations with no learning ability — it is not AI.',1),
(208,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What does a chatbot do?','A chatbot is an AI program that simulates conversation with users, answering questions and providing information.',1),
(209,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'How does Netflix use AI?','Netflix uses AI to recommend movies and shows based on your viewing history and preferences.',1),
(210,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'Which Ghanaian problem could AI help solve?','AI can analyse medical images to detect diseases like malaria and tuberculosis, improving healthcare in Ghana.',1),
(211,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What does IoT stand for?','IoT stands for Internet of Things — everyday objects connected to the internet to collect and share data.',1),
(212,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'Which of the following is an example of an IoT device?','A smart thermostat is an IoT device — it connects to the internet and can be controlled remotely.',1),
(213,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'How can IoT help farmers in Ghana?','IoT soil sensors measure moisture, temperature, and nutrients, sending data to farmers so they can irrigate crops more efficiently.',1),
(214,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'A smart electricity meter in Accra sends usage data automatically to ECG. What technology is this?','A smart electricity meter is an IoT device that automatically transmits consumption data to the utility company.',1),
(215,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What does a smart home device like Google Home allow you to do?','Google Home is a smart speaker that lets you control smart home devices, play music, and get information using voice commands.',1),
(216,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'Which of the following is needed for IoT devices to communicate?','IoT devices need internet connectivity (via Wi-Fi, 4G, or other networks) to communicate and share data.',1),
(217,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'Why is security important for IoT devices?','IoT devices collect personal data and if poorly secured, hackers can access them to spy, steal data, or disrupt services.',1),
(218,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What is a wearable IoT device?','A smartwatch is a wearable IoT device worn on the body that tracks health data and connects to the internet.',1),
(219,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'How many devices were connected to the internet globally by 2023?','By 2023, over 15 billion IoT devices were connected globally, with this number growing rapidly.',1),
(220,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'A hospital in Kumasi uses sensors to monitor patients remotely. What technology is this?','Remote patient monitoring using body sensors connected to the internet is an application of IoT in healthcare.',1),
(221,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What is cloud computing?','Cloud computing delivers computing services (storage, servers, software) over the internet rather than on local devices.',1),
(222,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'Which of the following is a cloud storage service used in Ghana?','Google Drive is a cloud storage service where users can store and access files from any device via the internet.',1),
(223,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What does SaaS stand for in cloud computing?','SaaS stands for Software as a Service — software delivered over the internet without local installation.',1),
(224,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'What is the main advantage of cloud storage over a USB drive?','Cloud storage can be accessed from any device anywhere with internet, unlike a USB drive which must be physically present.',1),
(225,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'Which company provides the iCloud cloud service?','iCloud is Apple\'s cloud storage and computing service for iOS and macOS users.',1),
(226,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'Gmail is an example of which cloud service model?','Gmail is a SaaS (Software as a Service) — email software delivered via the internet with no installation needed.',1),
(227,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'Why do many Ghanaian businesses use cloud computing?','Cloud computing reduces costs because businesses pay only for what they use, with no need to buy expensive servers.',1),
(228,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What does IaaS stand for?','IaaS stands for Infrastructure as a Service — cloud provision of virtual computers, storage, and networks.',1),
(229,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'Dropbox is an example of which type of cloud service?','Dropbox is a SaaS cloud storage and file-sharing service accessible via web browser or app.',1),
(230,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'What happens to your files when you save them to Google Drive?','Files saved to Google Drive are stored on Google\'s remote servers and can be accessed from any internet-connected device.',1),
(231,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'What is Big Data?','Big Data refers to extremely large datasets that are too large and complex for traditional software to process efficiently.',1),
(232,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'Which of the 5 Vs of Big Data describes the amount of data generated?','Volume refers to the massive amount (quantity) of data generated every second worldwide.',1),
(233,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'MTN Ghana processes millions of MoMo transactions daily. Which V of Big Data does this represent?','Velocity refers to the speed at which data is generated and must be processed in real time.',1),
(234,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'Data comes in many forms — text, images, video, audio. Which V of Big Data is this?','Variety refers to the many different types and formats of data generated from multiple sources.',1),
(235,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'How does Jumia Ghana use Big Data?','Jumia analyses customer purchase history and browsing data to recommend relevant products to each customer.',1),
(236,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'Which V of Big Data refers to the accuracy and trustworthiness of data?','Veracity refers to the quality, accuracy, and reliability of data — poor data leads to wrong decisions.',1),
(237,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'What tool is commonly used to process Big Data?','Apache Hadoop is a widely used framework for storing and processing very large datasets across computer clusters.',1),
(238,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'How can Ghana Revenue Authority (GRA) use Big Data?','GRA can use Big Data analytics to detect unusual tax patterns, identify potential tax evasion, and improve revenue collection.',1),
(239,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'Which V of Big Data refers to the usefulness of the data collected?','Value refers to the business insights and useful information that can be extracted from the data.',1),
(240,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'What is data analytics?','Data analytics is the process of examining datasets to draw conclusions, find patterns, and support decision-making.',1),
(241,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is blockchain technology?','Blockchain is a distributed digital ledger that records transactions across many computers, making records tamper-proof.',1),
(242,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'Which cryptocurrency uses blockchain technology?','Bitcoin uses blockchain technology — each transaction is recorded in a block linked to the previous one.',1),
(243,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'Why is blockchain considered secure?','Blockchain records are stored across thousands of computers simultaneously, making it nearly impossible to alter without detection.',1),
(244,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'The Bank of Ghana\'s e-Cedi (digital currency) uses which technology?','The e-Cedi is a Central Bank Digital Currency (CBDC) that uses blockchain-based distributed ledger technology.',1),
(245,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'How could blockchain help land registration in Ghana?','Blockchain can create a tamper-proof, transparent record of land ownership, preventing fraudulent title deed changes.',1),
(246,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is a "block" in blockchain?','A block is a container that holds a set of transaction records, a timestamp, and a link (hash) to the previous block.',1),
(247,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is cryptocurrency?','Cryptocurrency is a digital currency that uses cryptography and blockchain technology for secure transactions without central bank control.',1),
(248,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'Why is blockchain described as "decentralised"?','Blockchain has no single central authority — records are stored on thousands of computers worldwide, so no one entity controls it.',1),
(249,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is a "hash" in blockchain?','A hash is a unique digital fingerprint (alphanumeric code) that identifies each block and links it to the previous block.',1),
(250,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'How could a Ghanaian cocoa farmer benefit from blockchain?','Blockchain can track cocoa from farm to export, proving fair trade certification and allowing buyers to verify origin.',1),
(251,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What is a robot?','A robot is a programmable machine that can carry out complex actions automatically, often replacing human labour.',1),
(252,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'Zipline drones deliver blood in Ghana. What type of technology is Zipline?','Zipline operates autonomous delivery drones — a form of robotics and AI used for logistics in Ghana.',1),
(253,1,1,'mcq','S1/SS2','Robotics','Understand','Easy',1,1,'How are robots used in manufacturing?','Industrial robots perform repetitive tasks like welding, painting, and assembly on production lines with precision and speed.',1),
(254,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What language is commonly used to program simple robots?','Python is widely used for robotics programming due to its simplicity and powerful libraries for AI and hardware control.',1),
(255,1,1,'mcq','S1/SS2','Robotics','Understand','Easy',1,1,'Why are robots used in dangerous environments?','Robots can work in environments that are too dangerous for humans, such as nuclear plants, deep sea, or disaster zones.',1),
(256,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'What is 3D printing also known as?','3D printing is also known as Additive Manufacturing because objects are built by adding material layer by layer.',1),
(257,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'Which material is most commonly used in 3D printing?','PLA (Polylactic Acid) is the most common 3D printing material — a biodegradable plastic that melts and solidifies precisely.',1),
(258,1,1,'mcq','S1/SS2','3D Printing','Understand','Easy',1,1,'How could 3D printing help Ghana\'s healthcare sector?','3D printers can produce affordable prosthetic limbs and medical devices locally, reducing import costs and improving access.',1),
(259,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'What file format is typically used to send designs to a 3D printer?','STL (Standard Tessellation Language) is the most widely used file format for 3D printing designs.',1),
(260,1,1,'mcq','S1/SS2','3D Printing','Understand','Easy',1,1,'What is a key advantage of 3D printing over traditional manufacturing?','3D printing can create customised, complex shapes that are impossible or very expensive with traditional manufacturing methods.',1),
(261,1,1,'mcq','S1/SS2','AR and VR','Remember','Easy',1,1,'What does VR stand for?','VR stands for Virtual Reality — a fully immersive digital environment that replaces the real world.',1),
(262,1,1,'mcq','S1/SS2','AR and VR','Remember','Easy',1,1,'What does AR stand for?','AR stands for Augmented Reality — technology that overlays digital content onto the real world environment.',1),
(263,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'What is the difference between AR and VR?','VR creates a completely artificial environment replacing reality. AR adds digital elements to the real world environment.',1),
(264,1,1,'mcq','S1/SS2','AR and VR','Remember','Easy',1,1,'Which popular mobile game uses Augmented Reality?','Pokemon GO uses AR — players see virtual Pokemon overlaid on their real-world surroundings through their phone camera.',1),
(265,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'How could VR be used in Ghanaian schools?','VR allows students to take virtual field trips to historical sites, explore the human body, or visit places not physically accessible.',1),
(266,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What does MoMo stand for in Ghana?','MoMo stands for Mobile Money — a service allowing financial transactions via mobile phone without a bank account.',1),
(267,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'Which organisation regulates Mobile Money in Ghana?','The Bank of Ghana regulates Mobile Money services and all financial institutions operating in Ghana.',1),
(268,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What does GhIPSS stand for?','GhIPSS stands for Ghana Interbank Payment and Settlement Systems — it enables interoperability between payment networks.',1),
(269,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Easy',1,1,'What does GhIPSS interoperability mean for MoMo users?','GhIPSS interoperability allows users to send money between different MoMo networks (e.g. MTN to Vodafone) seamlessly.',1),
(270,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What is GhQR?','GhQR is Ghana\'s universal QR code payment standard that allows customers to pay merchants by scanning a QR code.',1),
(271,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'What is a recommendation system in AI?','A recommendation system analyses user behaviour and preferences to suggest relevant products, movies, or content automatically.',1),
(272,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'Which AI technique allows computers to understand spoken language?','Natural Language Processing (NLP) enables computers to understand, interpret, and respond to human language.',1),
(273,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What is computer vision?','Computer vision is an AI field that enables computers to interpret and understand images and videos like humans do.',1),
(274,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What is a smart city?','A smart city uses IoT, AI, and data to improve infrastructure, services, transportation, and quality of life for citizens.',1),
(275,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What does PaaS stand for in cloud computing?','PaaS stands for Platform as a Service — cloud provision of development tools and platforms for building applications.',1),
(276,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'Which of the following best describes deep learning?','Deep learning is a subset of machine learning using neural networks with many layers to recognise complex patterns.',1),
(277,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'How much data is created on the internet every day approximately?','Approximately 2.5 quintillion bytes of data are created every day globally from social media, sensors, transactions, and more.',1),
(278,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'Which mobile network was first to launch Mobile Money in Ghana?','MTN Ghana was the first to launch Mobile Money (MoMo) in Ghana in 2009, revolutionising financial inclusion.',1),
(279,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What is the name of the humanoid robot developed by Boston Dynamics?','Atlas is the advanced humanoid robot developed by Boston Dynamics capable of running, jumping, and doing gymnastics.',1),
(280,1,1,'mcq','S1/SS2','AR and VR','Remember','Easy',1,1,'Which device is used to experience Virtual Reality?','A VR headset (like Oculus Quest or PlayStation VR) is worn over the eyes to create an immersive virtual environment.',1),
(281,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What is a neural network in AI?','A neural network is a computing system inspired by the human brain, consisting of interconnected nodes that process information in layers.',1),
(282,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'Which AI application is used by banks to detect fraud?','Banks use AI fraud detection systems that analyse transaction patterns in real time to identify suspicious activity.',1),
(283,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What is the main risk of connecting too many IoT devices to a home network?','More IoT devices create more entry points for hackers — each poorly secured device can be a vulnerability on the network.',1),
(284,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'Why is cloud computing described as "pay-as-you-go"?','Users pay only for the computing resources they actually use, like a utility bill, rather than buying expensive hardware upfront.',1),
(285,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'What is the role of a data scientist?','A data scientist collects, analyses, and interprets large datasets to extract useful insights and support decision-making.',1),
(286,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is a "smart contract" in blockchain?','A smart contract is a self-executing program stored on a blockchain that automatically enforces agreement terms when conditions are met.',1),
(287,1,1,'mcq','S1/SS2','Robotics','Understand','Easy',1,1,'What is automation?','Automation is the use of technology (robots, computers, software) to perform tasks with minimal human intervention.',1),
(288,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'Which industry widely uses 3D printing to create aircraft parts?','The aerospace industry uses 3D printing to produce lightweight, complex aircraft components that are stronger and cheaper.',1),
(289,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Easy',1,1,'How does Mobile Money improve financial inclusion in Ghana?','Mobile Money allows unbanked Ghanaians in rural areas without bank branches to send, receive, and save money using a basic mobile phone.',1),
(290,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'How is AR used in medicine?','AR is used in surgery to overlay CT scan images onto the patient, helping surgeons see internal structures during operations.',1),
(291,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What does the term "algorithm" mean in AI?','An algorithm is a step-by-step set of rules or instructions that a computer follows to solve a problem or make a decision.',1),
(292,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'How is IoT used in traffic management in Accra?','Smart traffic systems use IoT sensors and cameras to monitor traffic flow and adjust signal timings automatically.',1),
(293,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What is Microsoft Azure?','Microsoft Azure is a cloud computing platform providing services like storage, AI, and virtual machines over the internet.',1),
(294,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'What is structured data?','Structured data is organised in a defined format (like rows and columns in a database) that is easy to search and analyse.',1),
(295,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is the name of the first and most well-known blockchain-based currency?','Bitcoin, created in 2009 by the pseudonymous Satoshi Nakamoto, is the first and most widely known blockchain cryptocurrency.',1),
(296,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What is the difference between a robot and a computer?','A robot interacts with the physical world through sensors and actuators to perform physical tasks, while a computer processes data electronically.',1),
(297,1,1,'mcq','S1/SS2','3D Printing','Understand','Easy',1,1,'What does "layer by layer" mean in 3D printing?','3D printers build objects by depositing thin layers of material one on top of another until the complete 3D shape is formed.',1),
(298,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What is Fintech?','Fintech (Financial Technology) refers to the use of technology to deliver financial services and products more efficiently.',1),
(299,1,1,'mcq','S1/SS2','AR and VR','Remember','Easy',1,1,'What is Mixed Reality (MR)?','Mixed Reality combines elements of both AR and VR, allowing digital and physical objects to interact in real time.',1),
(300,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'What ethical concern is raised by AI facial recognition systems?','AI facial recognition raises privacy concerns because it can track people without consent and may show racial or gender bias.',1),
(301,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What is the purpose of a virtual assistant like Google Assistant?','Google Assistant uses AI to answer questions, set reminders, control smart devices, and perform tasks using voice commands.',1),
(302,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What is a sensor in IoT?','A sensor is a device that detects and measures physical properties (temperature, light, motion) and converts them to digital data.',1),
(303,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What is the "public cloud"?','A public cloud is owned and operated by a third-party provider (like Google or Amazon) and shared among multiple users.',1),
(304,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'What is unstructured data?','Unstructured data has no predefined format — examples include emails, social media posts, videos, and audio files.',1),
(305,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'Why can blockchain records not be easily changed?','Each block contains a hash of the previous block. Changing one block breaks all subsequent hashes, making tampering obvious.',1),
(306,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What are actuators in robotics?','Actuators are components that enable a robot to move and interact with the physical environment, such as motors and pistons.',1),
(307,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'What is CAD software used for in 3D printing?','CAD (Computer-Aided Design) software is used to create 3D digital models that are then sent to the 3D printer.',1),
(308,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'Which Ghanaian organisation oversees GhIPSS?','GhIPSS was established by the Bank of Ghana to provide the infrastructure for electronic payments in Ghana.',1),
(309,1,1,'mcq','S1/SS2','AR and VR','Remember','Easy',1,1,'What is the Metaverse?','The Metaverse is a virtual shared space combining AR, VR, and the internet where users interact as avatars.',1),
(310,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What is supervised learning in machine learning?','Supervised learning trains AI models using labelled data — the correct answers are provided so the model learns from examples.',1),
(311,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'How does a smart streetlight save energy?','Smart streetlights use motion sensors and IoT connectivity to dim when no one is around and brighten when movement is detected.',1),
(312,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What is Amazon Web Services (AWS)?','AWS is Amazon\'s cloud computing platform offering storage, computing power, databases, and AI services over the internet.',1),
(313,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'What is real-time data processing?','Real-time processing analyses data immediately as it arrives, enabling instant decisions without storing it first.',1),
(314,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is an NFT?','NFT stands for Non-Fungible Token — a unique digital asset verified on a blockchain, used for digital art and collectibles.',1),
(315,1,1,'mcq','S1/SS2','Robotics','Understand','Easy',1,1,'What is a collaborative robot (cobot)?','A cobot is a robot designed to work safely alongside humans in the same workspace, assisting rather than replacing workers.',1),
(316,1,1,'mcq','S1/SS2','3D Printing','Understand','Easy',1,1,'Why is 3D printing useful for product prototyping?','3D printing allows designers to quickly produce physical prototypes to test designs before expensive mass production begins.',1),
(317,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What is mobile banking?','Mobile banking allows customers to access and manage their bank accounts through a smartphone app or USSD code.',1),
(318,1,1,'mcq','S1/SS2','AR and VR','Remember','Easy',1,1,'Which company developed the Oculus VR headset?','Meta (formerly Facebook) acquired Oculus and develops the Oculus Quest VR headset.',1),
(319,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What is natural language processing used for?','NLP enables computers to understand and generate human language, used in chatbots, translation, and voice assistants.',1),
(320,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'What is edge computing in relation to IoT?','Edge computing processes IoT data near the device rather than sending it to distant cloud servers, reducing delay.',1),
(321,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What is a private cloud?','A private cloud is dedicated to one organisation, providing the benefits of cloud computing with greater control and security.',1),
(322,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'How does NHIA (National Health Insurance Authority) use data in Ghana?','NHIA uses data analytics to track claims, detect fraud, and improve healthcare service delivery across Ghana.',1),
(323,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is a distributed ledger?','A distributed ledger is a database shared and synchronised across many computers simultaneously, with no central control.',1),
(324,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What is an autonomous vehicle?','An autonomous (self-driving) vehicle uses AI, sensors, and robotics to navigate and drive without human input.',1),
(325,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'What is bioprinting?','Bioprinting uses 3D printing technology with biological materials to create tissue, organs, and medical implants.',1),
(326,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Easy',1,1,'What is the significance of Susu in Ghanaian fintech?','Susu is a traditional Ghanaian savings system where a group contributes regularly. Digital Susu apps now automate this process.',1),
(327,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'How is VR used in military training?','VR creates realistic combat simulations for soldiers to train safely without live ammunition or physical risk.',1),
(328,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'What is unsupervised learning?','Unsupervised learning trains AI models on unlabelled data, allowing the model to find hidden patterns without guidance.',1),
(329,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What does RFID stand for?','RFID stands for Radio Frequency Identification — technology that uses radio waves to identify and track objects.',1),
(330,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'What is a hybrid cloud?','A hybrid cloud combines private and public cloud environments, allowing data and applications to move between them.',1),
(331,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'What is a data warehouse?','A data warehouse is a large storage system that collects and organises data from multiple sources for analysis and reporting.',1),
(332,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'How does blockchain help in supply chain management?','Blockchain creates an immutable record of every step in a supply chain, from production to delivery, ensuring transparency.',1),
(333,1,1,'mcq','S1/SS2','Robotics','Understand','Easy',1,1,'How are robots used in agriculture?','Agricultural robots plant seeds, apply pesticides, and harvest crops autonomously, increasing efficiency and reducing labour.',1),
(334,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'What is a filament in 3D printing?','A filament is the thread-like material (usually plastic) fed into a 3D printer and melted to build the object layer by layer.',1),
(335,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What is a USSD code?','A USSD code is a short numeric code (like *170#) that accesses mobile services including MoMo without internet.',1),
(336,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'How is AR used in retail shopping?','AR apps allow customers to virtually try on clothes, glasses, or see how furniture looks in their home before buying.',1),
(337,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What does the term "training data" mean in machine learning?','Training data is the large dataset used to teach an AI model to recognise patterns and make predictions.',1),
(338,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'How is IoT used in logistics and delivery?','IoT GPS trackers on vehicles and packages allow real-time location monitoring of shipments throughout the delivery process.',1),
(339,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'What is scalability in cloud computing?','Scalability means cloud resources can be increased or decreased quickly to match changing demand without buying new hardware.',1),
(340,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'Why is data privacy important in Big Data analysis?','Big Data often contains personal information. Without proper privacy controls, data can be misused, violating individuals\' rights.',1),
(341,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'What is cryptocurrency mining?','Cryptocurrency mining is the process of using computing power to validate blockchain transactions and earn new coins as a reward.',1),
(342,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What is artificial intelligence\'s role in robotics?','AI gives robots the ability to learn from their environment, make decisions, and improve their performance over time.',1),
(343,1,1,'mcq','S1/SS2','3D Printing','Understand','Easy',1,1,'How has 3D printing changed product customisation?','3D printing allows individual customers to have personalised products made to their exact specifications at relatively low cost.',1),
(344,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Easy',1,1,'What is e-levy in Ghana?','The e-Levy is a tax on electronic transfers including MoMo transactions above a daily threshold, collected by GRA.',1),
(345,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'What is motion sickness in VR?','VR motion sickness occurs when the visual movement in VR does not match the body\'s physical movement, causing discomfort.',1),
(346,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'How does AI help in weather forecasting?','AI processes vast amounts of atmospheric data from satellites and sensors to produce more accurate weather predictions.',1),
(347,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'What is a gateway in an IoT system?','An IoT gateway is a device that collects data from multiple IoT sensors and transmits it to the cloud or control system.',1),
(348,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'What does "uptime" mean for a cloud service?','Uptime is the percentage of time a cloud service is operational and available. High uptime (e.g. 99.9%) means reliable service.',1),
(349,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'What is Hadoop in Big Data?','Hadoop is an open-source framework that stores and processes Big Data across clusters of computers in parallel.',1),
(350,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Easy',1,1,'How does Hubtel support Ghanaian businesses?','Hubtel provides payment processing, delivery tracking, and messaging APIs that help Ghanaian businesses accept mobile payments.',1),
(351,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What is speech recognition?','Speech recognition converts spoken words into text using AI, enabling voice commands and transcription services.',1),
(352,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What is a smart refrigerator?','A smart refrigerator is an IoT device that tracks food inventory, suggests recipes, and can order groceries automatically.',1),
(353,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What is latency in cloud computing?','Latency is the time delay between a user\'s request and the cloud server\'s response — lower latency means faster service.',1),
(354,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'How does social media generate Big Data?','Social media platforms generate billions of posts, likes, shares, and comments every day, creating enormous datasets.',1),
(355,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'What problem does blockchain solve in voting systems?','Blockchain can create a transparent, tamper-proof voting record ensuring every vote is counted accurately and cannot be altered.',1),
(356,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What is a drone?','A drone (Unmanned Aerial Vehicle) is a remotely controlled or autonomous flying robot used for photography, delivery, and surveillance.',1),
(357,1,1,'mcq','S1/SS2','3D Printing','Understand','Easy',1,1,'What industries could benefit most from 3D printing in Ghana?','Healthcare (prosthetics), construction (affordable housing models), and education (teaching aids) could all benefit from 3D printing in Ghana.',1),
(358,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What is a digital wallet?','A digital wallet (e-wallet) is a software application that stores payment information for making electronic transactions.',1),
(359,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'How could AR help Ghanaian students learn history?','AR apps could overlay historical scenes on real locations — for example, showing what Elmina Castle looked like in the slave trade era.',1),
(360,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'What is bias in AI?','AI bias occurs when a model produces unfair or discriminatory results because the training data reflected existing human biases.',1),
(361,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'What is a connected car?','A connected car uses IoT, sensors, and internet connectivity to communicate with other vehicles, infrastructure, and the driver.',1),
(362,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'Why might a school in Ghana choose cloud-based software?','Cloud software requires no installation or expensive hardware — students can access it from any device including smartphones.',1),
(363,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'What is predictive analytics?','Predictive analytics uses historical data and AI to forecast future events, trends, or behaviours.',1),
(364,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is Ethereum?','Ethereum is a blockchain platform that supports smart contracts and decentralised applications (dApps) in addition to cryptocurrency.',1),
(365,1,1,'mcq','S1/SS2','Robotics','Understand','Easy',1,1,'What is the relationship between sensors and actuators in a robot?','Sensors collect information from the environment; actuators use that information to make the robot move or respond.',1),
(366,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'What is FDM in 3D printing?','FDM (Fused Deposition Modelling) is the most common 3D printing method that melts plastic filament and deposits it layer by layer.',1),
(367,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Easy',1,1,'How does QR code payment work at a Ghanaian market?','The merchant displays a GhQR code; the customer scans it with their MoMo app and enters the amount to pay instantly.',1),
(368,1,1,'mcq','S1/SS2','AR and VR','Remember','Easy',1,1,'What is haptic technology in VR?','Haptic technology provides physical sensations (vibrations, forces) to simulate touch in virtual reality experiences.',1),
(369,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What is image recognition?','Image recognition is an AI capability that identifies and classifies objects, people, or scenes within digital images.',1),
(370,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'How can IoT improve water management in Ghana?','IoT sensors on pipes and reservoirs detect leaks, monitor quality, and track usage to improve water distribution efficiency.',1),
(371,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'What is cloud backup?','Cloud backup automatically copies files to remote cloud servers, ensuring data can be recovered if a device is lost or damaged.',1),
(372,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'What is a data lake?','A data lake is a large storage repository that holds raw data in its native format until needed for analysis.',1),
(373,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'What is decentralised finance (DeFi)?','DeFi uses blockchain technology to provide financial services (lending, borrowing, trading) without traditional banks.',1),
(374,1,1,'mcq','S1/SS2','Robotics','Remember','Easy',1,1,'What is a robotic arm?','A robotic arm is a mechanical arm with joints that mimics a human arm, used in manufacturing, surgery, and assembly.',1),
(375,1,1,'mcq','S1/SS2','3D Printing','Remember','Easy',1,1,'What is SLA in 3D printing?','SLA (Stereolithography) uses ultraviolet light to cure liquid resin layer by layer, producing high-precision objects.',1),
(376,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What is agency banking in Ghana?','Agency banking allows authorised agents (like shops) to provide banking services on behalf of a bank in underserved areas.',1),
(377,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'How is AR used in navigation?','AR navigation apps overlay directions and information onto the live camera view, helping users find their way in real time.',1),
(378,1,1,'mcq','S1/SS2','Artificial Intelligence','Remember','Easy',1,1,'What is a decision tree in machine learning?','A decision tree is a model that makes predictions by following a series of yes/no questions, branching to a final answer.',1),
(379,1,1,'mcq','S1/SS2','Internet of Things','Remember','Easy',1,1,'What is a mesh network in IoT?','A mesh network is where IoT devices communicate directly with each other rather than all connecting to one central router.',1),
(380,1,1,'mcq','S1/SS2','Cloud Computing','Remember','Easy',1,1,'What is serverless computing?','Serverless computing lets developers run code without managing servers — the cloud provider handles all infrastructure automatically.',1),
(381,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'How can Ghana Statistical Service use Big Data?','GSS can use Big Data from mobile phones, satellite imagery, and administrative records to improve census accuracy and policy.',1),
(382,1,1,'mcq','S1/SS2','Blockchain','Remember','Easy',1,1,'What is a public blockchain?','A public blockchain is open for anyone to participate in, read, and verify transactions — Bitcoin and Ethereum are examples.',1),
(383,1,1,'mcq','S1/SS2','Robotics','Understand','Easy',1,1,'What is teleoperation in robotics?','Teleoperation allows humans to control robots remotely, used in surgery, bomb disposal, and deep-sea exploration.',1),
(384,1,1,'mcq','S1/SS2','3D Printing','Understand','Easy',1,1,'How is 3D printing used in construction?','3D printers can print concrete structures, creating affordable housing and complex architectural shapes more quickly.',1),
(385,1,1,'mcq','S1/SS2','Ghana Fintech','Remember','Easy',1,1,'What is Zeepay?','Zeepay is a Ghanaian fintech company that provides cross-border money transfer and mobile wallet services.',1),
(386,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'How could VR help trainee doctors in Ghana?','VR allows medical students to practise surgical procedures in a safe virtual environment before operating on real patients.',1),
(387,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'What is transfer learning?','Transfer learning uses knowledge gained from training one AI model to improve the performance of a different related model.',1),
(388,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'What is a digital twin?','A digital twin is a virtual model of a physical object or system that receives real-time data from sensors to simulate performance.',1),
(389,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'What is cloud migration?','Cloud migration is the process of moving data, applications, and services from on-premises infrastructure to cloud servers.',1),
(390,1,1,'mcq','S1/SS2','Big Data','Understand','Easy',1,1,'What is sentiment analysis?','Sentiment analysis uses AI to determine whether text (social media posts, reviews) expresses positive, negative, or neutral opinion.',1),
(391,1,1,'mcq','S1/SS2','Blockchain','Understand','Easy',1,1,'How can Ghanaian students benefit from learning about blockchain?','Understanding blockchain prepares students for careers in fintech, cybersecurity, and digital governance as Ghana adopts these technologies.',1),
(392,1,1,'mcq','S1/SS2','Robotics','Understand','Easy',1,1,'What is swarm robotics?','Swarm robotics uses many simple robots working together in coordination, inspired by the behaviour of ants or bees.',1),
(393,1,1,'mcq','S1/SS2','3D Printing','Understand','Easy',1,1,'What limitations does 3D printing currently have?','Current limitations include slow printing speed for large objects, limited materials, and high costs for industrial-grade printers.',1),
(394,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Easy',1,1,'What is the importance of cybersecurity in Ghana\'s fintech sector?','As digital payments grow, cybercriminals target MoMo accounts and banking apps — strong cybersecurity protects users\' money.',1),
(395,1,1,'mcq','S1/SS2','AR and VR','Understand','Easy',1,1,'What is spatial computing?','Spatial computing is the use of technology to interact with digital content in physical 3D space, combining AR, VR, and AI.',1),
(396,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Easy',1,1,'What is the Turing Test?','The Turing Test evaluates whether an AI can exhibit intelligent behaviour indistinguishable from a human in conversation.',1),
(397,1,1,'mcq','S1/SS2','Internet of Things','Understand','Easy',1,1,'How does IoT support precision agriculture in Ghana?','IoT sensors measure soil moisture, weather, and crop health, enabling farmers to apply water and fertiliser only where needed.',1),
(398,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Easy',1,1,'What is a Content Delivery Network (CDN)?','A CDN distributes content across servers worldwide so users receive data from the nearest server, reducing loading time.',1),
(399,1,1,'mcq','S1/SS2','Big Data','Remember','Easy',1,1,'What does ETL stand for in data processing?','ETL stands for Extract, Transform, Load — a process for moving data from source systems into a data warehouse.',1),
(400,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Easy',1,1,'What makes Ghana a leader in African fintech?','Ghana''s high mobile penetration, GhIPSS infrastructure, and Bank of Ghana''s regulatory support make it a leading African fintech hub.',1);
INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(401,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'Ama uses a music app that suggests songs based on what she has listened to before. Which AI technique is being used?','Recommendation systems use collaborative filtering and machine learning to suggest content based on user history and similar users.',1),
(402,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'A Ghanaian hospital uses AI to detect malaria parasites in blood slides automatically. What type of AI is this?','Computer vision and image recognition AI can analyse microscopy images to identify malaria parasites with high accuracy.',1),
(403,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'Kofi receives a WhatsApp message in Twi and Google translates it to English automatically. What AI feature enables this?','Neural Machine Translation (NMT) uses deep learning to translate between languages, including local languages like Twi.',1),
(404,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Medium',1,1,'What is the difference between AI, machine learning, and deep learning?','AI is the broadest concept. Machine learning is a subset of AI. Deep learning is a subset of machine learning using neural networks.',1),
(405,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'A bank uses AI to analyse customer transactions and flag unusual ones for fraud investigation. What is this system called?','AI-powered anomaly detection systems monitor transaction patterns and flag deviations that may indicate fraud.',1),
(406,1,1,'mcq','S1/SS2','Artificial Intelligence','Analyse','Medium',1,1,'Nana notices that an AI recruitment tool rejects more female applicants than male ones. What is this an example of?','This is AI bias caused by training data that reflected historical gender discrimination in hiring — the AI learned and replicated the bias.',1),
(407,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'A farmer in Brong-Ahafo uses an app that identifies crop diseases from photos. Which AI technology powers this?','Image recognition AI trained on plant disease datasets can identify crop diseases from photographs with high accuracy.',1),
(408,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'Abena asks Google Assistant "What is the weather in Accra tomorrow?" What AI technologies are involved?','Speech recognition converts voice to text, NLP understands the query, and a knowledge base retrieves the weather information.',1),
(409,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Medium',1,1,'Why do AI models need large amounts of training data?','More training data exposes the AI to more examples and variations, helping it learn patterns more accurately and generalise better.',1),
(410,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'An AI content moderation system removes posts containing hate speech on a social platform. What challenge does this present?','AI moderation may incorrectly remove legitimate posts (false positives) or miss harmful content in local languages like Twi or Ga.',1),
(411,1,1,'mcq','S1/SS2','Internet of Things','Apply','Medium',1,1,'A smart waste management system in Accra uses sensors in bins to alert collection trucks only when bins are full. What benefit does this provide?','Sensor-based waste management optimises collection routes, reduces fuel consumption, and ensures timely waste removal.',1),
(412,1,1,'mcq','S1/SS2','Internet of Things','Apply','Medium',1,1,'Kweku''s school uses IoT attendance system where students tap their ID cards at the gate. What technology is this?','RFID-based IoT attendance systems use contactless card readers to automatically record student arrival and departure times.',1),
(413,1,1,'mcq','S1/SS2','Internet of Things','Understand','Medium',1,1,'A hospital connects patient monitors to a central IoT dashboard. What security risk does this create?','Medical IoT devices if poorly secured can be hacked, allowing attackers to access patient data or interfere with equipment.',1),
(414,1,1,'mcq','S1/SS2','Internet of Things','Apply','Medium',1,1,'Fatima''s family has a smart home system. When she leaves home, the system automatically turns off lights and locks doors. What technology enables this?','IoT automation uses sensors (door/location) and programmable rules to automatically control home devices without manual input.',1),
(415,1,1,'mcq','S1/SS2','Internet of Things','Analyse','Medium',1,1,'A city installs IoT air quality sensors across Accra. The data shows pollution peaks between 7-9am. What conclusion can planners draw?','Peak pollution at 7-9am corresponds to morning rush hour traffic. Planners can use this data to develop traffic management and emission policies.',1),
(416,1,1,'mcq','S1/SS2','Internet of Things','Apply','Medium',1,1,'A cocoa farmer uses IoT soil sensors and receives alerts on his phone when moisture drops below a threshold. What is the benefit?','Automated soil moisture alerts enable precision irrigation — water is applied only when needed, saving water and reducing costs.',1),
(417,1,1,'mcq','S1/SS2','Internet of Things','Understand','Medium',1,1,'What is the challenge of powering IoT devices in rural Ghana?','Many rural areas in Ghana lack reliable electricity. IoT devices in these areas need solar power or battery solutions.',1),
(418,1,1,'mcq','S1/SS2','Internet of Things','Apply','Medium',1,1,'A logistics company uses GPS IoT trackers on delivery vans. What operational improvements does this enable?','Real-time GPS tracking allows route optimisation, estimated delivery times, theft detection, and driver performance monitoring.',1),
(419,1,1,'mcq','S1/SS2','Internet of Things','Understand','Medium',1,1,'What communication protocol do many IoT devices use for short-range wireless communication?','Bluetooth Low Energy (BLE) is widely used for short-range IoT device communication due to its low power consumption.',1),
(420,1,1,'mcq','S1/SS2','Internet of Things','Analyse','Medium',1,1,'An IoT system collects data from 10,000 sensors every second. What computing challenge does this create?','Processing 10,000 data points per second requires significant computing power, storage, and fast data processing infrastructure.',1),
(421,1,1,'mcq','S1/SS2','Cloud Computing','Apply','Medium',1,1,'Ama''s school uses Google Classroom. Students submit assignments from home. Which cloud service model is this?','Google Classroom is SaaS — educational software delivered via the internet without installation on school computers.',1),
(422,1,1,'mcq','S1/SS2','Cloud Computing','Apply','Medium',1,1,'A startup in Accra builds a mobile app using Amazon Web Services for servers. Which cloud model are they using?','Using AWS virtual servers is IaaS (Infrastructure as a Service) — the startup rents computing infrastructure from Amazon.',1),
(423,1,1,'mcq','S1/SS2','Cloud Computing','Apply','Medium',1,1,'Kofi works on a spreadsheet in Google Sheets simultaneously with classmates in different locations. What cloud feature enables this?','Real-time collaboration in cloud applications allows multiple users to edit the same document simultaneously from different locations.',1),
(424,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Medium',1,1,'A Ghanaian company stores all customer data exclusively on servers in the USA. What concern does this raise?','Data sovereignty concerns arise when data about Ghanaian citizens is stored in foreign jurisdictions subject to different laws.',1),
(425,1,1,'mcq','S1/SS2','Cloud Computing','Apply','Medium',1,1,'A hospital uses cloud storage for patient records. A ransomware attack encrypts their local computers. What advantage does cloud storage provide?','Cloud-stored data with proper backups can be recovered quickly after a ransomware attack, minimising disruption to hospital services.',1),
(426,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Medium',1,1,'What is a Service Level Agreement (SLA) in cloud computing?','An SLA is a contract between the cloud provider and customer defining guaranteed uptime, performance, and support standards.',1),
(427,1,1,'mcq','S1/SS2','Cloud Computing','Apply','Medium',1,1,'A school in Tamale has limited computers. Students use smartphones to access cloud-based learning materials. What advantage does this show?','Cloud computing enables access to resources from any internet-connected device, democratising access to digital content.',1),
(428,1,1,'mcq','S1/SS2','Cloud Computing','Understand','Medium',1,1,'What is auto-scaling in cloud computing?','Auto-scaling automatically increases or decreases computing resources based on current demand, ensuring performance without waste.',1),
(429,1,1,'mcq','S1/SS2','Cloud Computing','Apply','Medium',1,1,'Abena''s e-commerce business grows from 100 to 10,000 customers during a sale. Her cloud server handles the load automatically. What cloud feature is this?','Auto-scaling (elasticity) allows cloud services to dynamically adjust capacity based on traffic, handling sudden demand spikes.',1),
(430,1,1,'mcq','S1/SS2','Cloud Computing','Analyse','Medium',1,1,'A company moves its entire IT infrastructure to the cloud but then the cloud provider suffers a major outage. What lesson does this teach?','Cloud outages show the risk of total dependence on one provider. Businesses should use multi-cloud or hybrid strategies for resilience.',1),
(431,1,1,'mcq','S1/SS2','Big Data','Apply','Medium',1,1,'MTN Ghana analyses MoMo transaction data to predict which customers are likely to default on loans. What is this called?','This is predictive analytics — using historical transaction data and machine learning to forecast future credit behaviour.',1),
(432,1,1,'mcq','S1/SS2','Big Data','Apply','Medium',1,1,'A supermarket analyses purchase data and notices Ghanaian customers buy more rice before pay day. How can they use this?','The supermarket can optimise stock levels, run targeted promotions, and schedule deliveries to align with demand patterns.',1),
(433,1,1,'mcq','S1/SS2','Big Data','Understand','Medium',1,1,'What ethical issue arises when Big Data is used for targeted political advertising?','Using personal data to micro-target political messages without consent can manipulate voters and undermine democratic processes.',1),
(434,1,1,'mcq','S1/SS2','Big Data','Apply','Medium',1,1,'GRA uses data analytics to compare declared income with lifestyle indicators (car ownership, travel). What is this approach?','This is data-driven tax compliance analysis — cross-referencing multiple datasets to identify potential tax evasion.',1),
(435,1,1,'mcq','S1/SS2','Big Data','Analyse','Medium',1,1,'A health researcher analyses patient records from 50 hospitals to find patterns in malaria outbreaks. What challenge do they face?','Patient data across hospitals exists in different formats and systems, requiring complex data integration before analysis.',1),
(436,1,1,'mcq','S1/SS2','Big Data','Apply','Medium',1,1,'Accra Metropolitan Assembly uses satellite imagery and sensor data to monitor flood-prone areas. What is this an example of?','Using Big Data from multiple sources (satellite, sensors) for urban planning and disaster management is smart city analytics.',1),
(437,1,1,'mcq','S1/SS2','Big Data','Understand','Medium',1,1,'What is the difference between data and information?','Data is raw unprocessed facts (numbers, text). Information is data that has been processed and given meaning in context.',1),
(438,1,1,'mcq','S1/SS2','Big Data','Apply','Medium',1,1,'A bank uses real-time analytics on MoMo transactions. A customer transfers GHS 50,000 at 2am. The system flags it. Why?','Real-time fraud detection identifies anomalous patterns — large night-time transfers may indicate account compromise.',1),
(439,1,1,'mcq','S1/SS2','Big Data','Understand','Medium',1,1,'What is the General Data Protection Regulation (GDPR) equivalent in Ghana?','Ghana''s Data Protection Act 2012 (Act 843) is the national law governing collection and use of personal data.',1),
(440,1,1,'mcq','S1/SS2','Big Data','Analyse','Medium',1,1,'A company collects data from users without their knowledge. What law in Ghana would this violate?','Collecting personal data without consent violates Ghana''s Data Protection Act 2012 (Act 843), which requires explicit consent.',1),
(441,1,1,'mcq','S1/SS2','Blockchain','Apply','Medium',1,1,'Kweku wants to send money from Ghana to the UK instantly without a bank. Which technology makes this possible?','Cryptocurrency on blockchain networks enables peer-to-peer international transfers without banks, settling in minutes.',1),
(442,1,1,'mcq','S1/SS2','Blockchain','Apply','Medium',1,1,'A Ghanaian cocoa exporter uses blockchain to prove to European buyers that their cocoa is sustainably sourced. How?','Blockchain records every step of the supply chain — from farm to export — creating an immutable, verifiable audit trail.',1),
(443,1,1,'mcq','S1/SS2','Blockchain','Understand','Medium',1,1,'Why do some governments worry about cryptocurrency?','Governments worry cryptocurrency enables tax evasion, money laundering, and bypassing of financial regulations and sanctions.',1),
(444,1,1,'mcq','S1/SS2','Blockchain','Apply','Medium',1,1,'A land dispute in Kumasi could be resolved using blockchain. How would this work?','A blockchain land registry records ownership permanently and transparently — any fraudulent claim is immediately verifiable as false.',1),
(445,1,1,'mcq','S1/SS2','Blockchain','Analyse','Medium',1,1,'Why is cryptocurrency mining environmentally controversial?','Cryptocurrency mining (especially Bitcoin) consumes enormous amounts of electricity, contributing significantly to carbon emissions.',1),
(446,1,1,'mcq','S1/SS2','Blockchain','Apply','Medium',1,1,'A patient''s medical records are stored on a blockchain. What advantage does this offer over traditional hospital records?','Blockchain medical records are secure, portable, and can be accessed by authorised healthcare providers anywhere, improving continuity of care.',1),
(447,1,1,'mcq','S1/SS2','Blockchain','Understand','Medium',1,1,'What is a private blockchain?','A private blockchain restricts participation to authorised users only, offering more control than a public blockchain.',1),
(448,1,1,'mcq','S1/SS2','Blockchain','Apply','Medium',1,1,'Ghana''s DVLA wants to use blockchain for vehicle registration. What problem would this solve?','Blockchain vehicle registration prevents fraudulent ownership transfers and ensures accurate, tamper-proof vehicle history records.',1),
(449,1,1,'mcq','S1/SS2','Blockchain','Analyse','Medium',1,1,'A student buys a rare digital artwork as an NFT. What does owning the NFT actually mean?','Owning an NFT proves ownership of a unique token on the blockchain — the actual image file may still be accessible to anyone.',1),
(450,1,1,'mcq','S1/SS2','Blockchain','Apply','Medium',1,1,'A Ghanaian startup creates a blockchain-based system for students to store and share academic certificates. What problem does this solve?','Blockchain certificates cannot be forged — employers and institutions can instantly verify authentic certificates on the blockchain.',1),
(451,1,1,'mcq','S1/SS2','Robotics','Apply','Medium',1,1,'Accra''s Korle-Bu Hospital uses a robot to assist surgeons in operations. What advantage does this offer?','Surgical robots provide greater precision, reduce human error, enable minimally invasive procedures, and improve patient recovery.',1),
(452,1,1,'mcq','S1/SS2','Robotics','Apply','Medium',1,1,'A Ghanaian school uses a robot in ICT class that students program using block-based coding. What is this called?','Educational robots teach programming, problem-solving, and computational thinking in an engaging, hands-on way.',1),
(453,1,1,'mcq','S1/SS2','Robotics','Understand','Medium',1,1,'What ethical concern arises when robots replace human workers in a factory?','Automation displaces workers creating unemployment — society must consider retraining programmes and social safety nets.',1),
(454,1,1,'mcq','S1/SS2','Robotics','Apply','Medium',1,1,'Zipline uses autonomous drones to deliver medicine to remote areas of Ghana. What problem does this solve?','In areas without good roads, drone delivery reaches remote communities much faster than vehicles, saving lives with timely medicine.',1),
(455,1,1,'mcq','S1/SS2','Robotics','Analyse','Medium',1,1,'A robot vacuum cleaner uses sensors to navigate a room without hitting furniture. What AI technique does it use?','Robot vacuums use SLAM (Simultaneous Localisation and Mapping) — building a map of the environment while navigating it.',1),
(456,1,1,'mcq','S1/SS2','3D Printing','Apply','Medium',1,1,'A prosthetist in Accra uses a 3D printer to make a prosthetic hand for a patient. What is the main advantage?','3D-printed prosthetics can be custom-fitted to each patient''s body measurements and produced at a fraction of traditional costs.',1),
(457,1,1,'mcq','S1/SS2','3D Printing','Apply','Medium',1,1,'An architect uses 3D printing to show clients a physical model of a building design. What stage of design is this?','3D-printed architectural models are used in the prototyping stage to visualise and communicate designs to clients before construction.',1),
(458,1,1,'mcq','S1/SS2','3D Printing','Understand','Medium',1,1,'Why might a company 3D print a spare part for a machine instead of ordering it from a supplier?','3D printing spare parts on demand eliminates waiting time and shipping costs, and is ideal for rare or discontinued parts.',1),
(459,1,1,'mcq','S1/SS2','3D Printing','Analyse','Medium',1,1,'A school buys a 3D printer for GHS 8,000. After 2 years, students have printed 500 models. Was it a good investment?','Benefits include hands-on learning, creativity, and STEM skills development — evaluate against curriculum goals and usage frequency.',1),
(460,1,1,'mcq','S1/SS2','3D Printing','Apply','Medium',1,1,'Scientists use 3D bioprinting to create liver tissue for drug testing. Why is this significant?','Bioprinted tissue eliminates the need for some animal testing and provides more accurate human-specific results for drug development.',1),
(461,1,1,'mcq','S1/SS2','Ghana Fintech','Apply','Medium',1,1,'Ama needs to pay her school fees at KNUST. The school accepts GhQR payments. Walk through the steps she would follow.','Ama opens her MoMo app, selects Pay with QR, scans the school''s GhQR code, enters the amount, and confirms with her PIN.',1),
(462,1,1,'mcq','S1/SS2','Ghana Fintech','Apply','Medium',1,1,'A market trader in Makola does not have a bank account but uses MTN MoMo to receive payments. What financial service model is this?','Mobile Money provides financial services (payments, transfers, savings) to the unbanked population through mobile phones.',1),
(463,1,1,'mcq','S1/SS2','Ghana Fintech','Understand','Medium',1,1,'Why did Ghana''s e-Levy face public opposition when introduced in 2022?','Many Ghanaians felt the e-Levy unfairly taxed everyday mobile money transactions, adding cost to a service used by the poor.',1),
(464,1,1,'mcq','S1/SS2','Ghana Fintech','Apply','Medium',1,1,'Kofi receives a call claiming to be from MTN asking for his MoMo PIN. What should he do?','Legitimate companies never ask for PINs over phone or SMS. Kofi should hang up and report the number to MTN Ghana.',1),
(465,1,1,'mcq','S1/SS2','Ghana Fintech','Analyse','Medium',1,1,'How has Mobile Money changed the livelihoods of Ghanaian market women?','MoMo enables market women to receive payments safely without carrying cash, access savings, and qualify for mobile loans.',1),
(466,1,1,'mcq','S1/SS2','AR and VR','Apply','Medium',1,1,'Accra Museum uses AR to show visitors how ancient Ghanaian artefacts were used in their original context. What technology makes this possible?','AR markers on exhibits trigger smartphone apps to display 3D animations showing historical context of the artefacts.',1),
(467,1,1,'mcq','S1/SS2','AR and VR','Apply','Medium',1,1,'A student uses VR to practise giving a speech in front of a virtual audience before their real presentation. What is the benefit?','VR public speaking practice reduces anxiety in a safe environment, allowing repeated practice without real-world consequences.',1),
(468,1,1,'mcq','S1/SS2','AR and VR','Understand','Medium',1,1,'What is the difference between a 360-degree video and true VR?','A 360-degree video is pre-recorded footage you can look around in. True VR is a real-time interactive environment you can navigate.',1),
(469,1,1,'mcq','S1/SS2','AR and VR','Apply','Medium',1,1,'An engineering company uses AR to overlay maintenance instructions on machinery during repairs. What is the advantage?','AR overlays provide real-time guidance, reducing errors and training time while keeping the technician''s hands free for work.',1),
(470,1,1,'mcq','S1/SS2','AR and VR','Analyse','Medium',1,1,'VR headsets currently cost between $300–$1500. How does this affect adoption in Ghana?','High costs limit access to VR mainly to institutions and wealthy individuals in Ghana. Affordable alternatives like cardboard VR help.',1),
(471,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'A student uses ChatGPT to write an essay and submits it as their own work. What ethical issue does this raise?','Using AI to complete academic work without disclosure is academic dishonesty — it misrepresents the student''s own abilities.',1),
(472,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Medium',1,1,'What is explainable AI (XAI)?','Explainable AI provides transparent reasoning for its decisions so users can understand why a particular output was produced.',1),
(473,1,1,'mcq','S1/SS2','Internet of Things','Apply','Medium',1,1,'Smart electricity meters in Accra send usage data hourly to ECG. How does this benefit consumers?','Smart meters provide detailed usage data, helping consumers identify energy-hungry appliances and reduce electricity bills.',1),
(474,1,1,'mcq','S1/SS2','Cloud Computing','Apply','Medium',1,1,'Abena studies for WASSCE using Khan Academy on her smartphone. Which cloud model enables this free global access?','Khan Academy is SaaS delivered via the internet. Its freemium model is funded by donations, making education globally accessible.',1),
(475,1,1,'mcq','S1/SS2','Big Data','Analyse','Medium',1,1,'Why is it problematic for an AI health system trained on Western patient data to be used in Ghana?','Western training data may not reflect Ghanaian disease patterns, genetics, or conditions, leading to inaccurate diagnoses.',1),
(476,1,1,'mcq','S1/SS2','Blockchain','Apply','Medium',1,1,'A Ghanaian university issues blockchain-based degree certificates. An employer in London wants to verify Kweku''s certificate. How?','The employer scans the QR code on the digital certificate, which retrieves the verified record directly from the blockchain.',1),
(477,1,1,'mcq','S1/SS2','Robotics','Apply','Medium',1,1,'Ghana''s Electoral Commission wants to use robots to count ballots electronically. What concerns might arise?','Concerns include technical malfunctions, hacking risks, transparency of the counting process, and public trust in automated systems.',1),
(478,1,1,'mcq','S1/SS2','3D Printing','Apply','Medium',1,1,'A Ghanaian design student creates a traditional kente-inspired jewellery design and 3D prints it. What opportunity does this create?','The student can produce, customise, and sell unique jewellery items at lower cost, combining traditional design with modern technology.',1),
(479,1,1,'mcq','S1/SS2','Ghana Fintech','Analyse','Medium',1,1,'More Ghanaians now have MoMo accounts than bank accounts. What does this suggest about financial inclusion?','Mobile Money has been more effective than traditional banking in reaching Ghana''s unbanked population, especially in rural areas.',1),
(480,1,1,'mcq','S1/SS2','AR and VR','Apply','Medium',1,1,'An architect uses VR to walk through a building before construction begins. What problem does this solve?','VR walkthroughs reveal design flaws, spatial issues, and user experience problems before expensive construction begins.',1),
(481,1,1,'mcq','S1/SS2','Artificial Intelligence','Understand','Medium',1,1,'What is reinforcement learning?','Reinforcement learning trains AI by rewarding correct actions and penalising wrong ones, like training a dog with treats.',1),
(482,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'Google Maps uses AI to suggest the fastest route from Accra to Kumasi. What data does it use?','Google Maps AI analyses real-time traffic data, historical patterns, road incidents, and speed data from millions of users.',1),
(483,1,1,'mcq','S1/SS2','Internet of Things','Understand','Medium',1,1,'What is protocol in IoT communication?','A protocol is a set of rules governing how IoT devices communicate and exchange data, such as MQTT, HTTP, or CoAP.',1),
(484,1,1,'mcq','S1/SS2','Cloud Computing','Analyse','Medium',1,1,'A government stores confidential citizen data on a US-based public cloud. Critics argue this is a sovereignty issue. Why?','US laws (like the CLOUD Act) can compel US companies to hand over data stored in their servers, even data from other countries.',1),
(485,1,1,'mcq','S1/SS2','Big Data','Apply','Medium',1,1,'Accra''s Korle Bu hospital uses patient data to predict which patients are at risk of sepsis within 24 hours. What is this?','Predictive AI using clinical Big Data (vital signs, lab results, history) identifies at-risk patients for early intervention.',1),
(486,1,1,'mcq','S1/SS2','Blockchain','Analyse','Medium',1,1,'Why does a blockchain transaction take longer to confirm than a regular bank transfer?','Blockchain transactions must be validated by multiple network nodes through consensus mechanisms, which takes time but ensures security.',1),
(487,1,1,'mcq','S1/SS2','Robotics','Understand','Medium',1,1,'What is computer vision''s role in autonomous vehicles?','Computer vision helps self-driving cars identify roads, pedestrians, traffic signs, and obstacles in real time from camera feeds.',1),
(488,1,1,'mcq','S1/SS2','3D Printing','Analyse','Medium',1,1,'Ghana produces a lot of plastic waste. How could 3D printing contribute to solving this?','Recycled plastic can be shredded and re-extruded into 3D printing filament, turning waste into raw material for new products.',1),
(489,1,1,'mcq','S1/SS2','Ghana Fintech','Apply','Medium',1,1,'A Ghanaian trader uses Jumo to access a mobile loan of GHS 500. How is this different from a traditional bank loan?','Mobile loans from fintech companies like Jumo are approved algorithmically using MoMo transaction history — no paperwork or collateral needed.',1),
(490,1,1,'mcq','S1/SS2','AR and VR','Analyse','Medium',1,1,'A VR game company creates a realistic war simulation. What ethical concerns does this raise?','Realistic violence in VR may desensitise users, blur the line between virtual and real, and raise concerns about impact on mental health.',1),
(491,1,1,'mcq','S1/SS2','Artificial Intelligence','Apply','Medium',1,1,'Nana''s teacher uses AI to grade multiple-choice exams automatically. What is a key limitation of this approach?','AI can only mark questions with definitive answers — essays, creative writing, and nuanced responses still require human judgement.',1),
(492,1,1,'mcq','S1/SS2','Internet of Things','Analyse','Medium',1,1,'A city connects 1 million IoT devices to the internet. What cybersecurity challenge does this scale create?','Each IoT device is a potential attack surface. Managing security updates, passwords, and vulnerabilities at this scale is extremely complex.',1),
(493,1,1,'mcq','S1/SS2','Cloud Computing','Apply','Medium',1,1,'A school discovers that its cloud provider is reading student documents for advertising purposes. What should the school do?','The school should review the Terms of Service, switch to a privacy-respecting provider, and report the violation to data protection authorities.',1),
(494,1,1,'mcq','S1/SS2','Big Data','Apply','Medium',1,1,'A political party in Ghana buys voter data from a private company to target voters on social media. What law may they have violated?','Purchasing and using personal data without consent may violate Ghana''s Data Protection Act 2012 (Act 843).',1),
(495,1,1,'mcq','S1/SS2','Blockchain','Apply','Medium',1,1,'A Ghanaian farmer wants to receive payment for cocoa directly from a UK buyer using cryptocurrency, bypassing banks. What is the main risk?','Cryptocurrency values fluctuate dramatically — the farmer may receive far less (or more) than expected due to price volatility.',1),
(496,1,1,'mcq','S1/SS2','Robotics','Apply','Medium',1,1,'A Ghanaian secondary school participates in a national robotics competition. Students build a robot that follows a line. What sensors does it need?','Line-following robots use infrared (IR) sensors to detect the contrast between a dark line and light surface to follow a path.',1),
(497,1,1,'mcq','S1/SS2','3D Printing','Apply','Medium',1,1,'A teacher wants students to design and print a model of the Volta River dam. What skills will they develop?','Students develop spatial reasoning, CAD design skills, engineering thinking, and understanding of physical structures through 3D printing.',1),
(498,1,1,'mcq','S1/SS2','Ghana Fintech','Apply','Medium',1,1,'A woman in a village without any bank branch needs to pay her child''s school fees in Accra. What is the best solution?','MoMo (Mobile Money) allows her to send the school fees directly to the school''s number from her mobile phone instantly.',1),
(499,1,1,'mcq','S1/SS2','AR and VR','Apply','Medium',1,1,'A tourism board uses AR to create a virtual tour of Kakum National Park that people can experience from anywhere. What benefit does this have?','Virtual AR/VR tourism allows people worldwide to experience Ghana''s attractions, boosting interest and potentially increasing actual visits.',1),
(500,1,1,'mcq','S1/SS2','Artificial Intelligence','Analyse','Medium',1,1,'An AI is 95% accurate at diagnosing malaria. A doctor is 90% accurate. Should the AI replace the doctor?','AI can assist but should not replace doctors — the 5% error rate can cause harm, AI cannot explain decisions to patients, and medical care involves empathy.',1);
INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(501,1,1,'mcq','S1/SS2','Artificial Intelligence','Analyse','Hard',1,1,'An AI model achieves 99% accuracy on training data but only 70% on new data. What is this problem called, and how can it be solved?','This is overfitting — the model memorised training data rather than learning general patterns. Solutions include more diverse training data, regularisation, and cross-validation.',1),
(502,1,1,'mcq','S1/SS2','Artificial Intelligence','Analyse','Hard',1,1,'Ghana wants to develop an AI system for the judicial system to predict recidivism (re-offending). What ethical concerns make this controversial?','The system could embed racial or socioeconomic bias, remove human judgement from legal decisions, and punish people for predicted rather than actual behaviour.',1),
(503,1,1,'mcq','S1/SS2','Artificial Intelligence','Analyse','Hard',1,1,'A deep learning image classifier is 98% accurate but cannot explain why it classified an image a certain way. Why is this problematic in medicine?','In high-stakes medical decisions, unexplainable AI cannot be trusted — doctors need to understand the reasoning to verify, challenge, or explain decisions to patients.',1),
(504,1,1,'mcq','S1/SS2','Artificial Intelligence','Analyse','Hard',1,1,'An AI facial recognition system deployed by Ghanaian police misidentifies more dark-skinned faces than light-skinned ones. What is the root cause?','The training dataset likely had fewer dark-skinned faces, causing the model to perform poorly on underrepresented demographics — a classic data bias problem.',1),
(505,1,1,'mcq','S1/SS2','Artificial Intelligence','Analyse','Hard',1,1,'A company uses AI to make all hiring decisions with no human review. An applicant is rejected. They ask why. The company says "the AI decided." What right is violated?','Individuals have a right to explanation and human review for automated decisions that significantly affect them under data protection principles.',1),
(506,1,1,'mcq','S1/SS2','Internet of Things','Analyse','Hard',1,1,'A manufacturer ships 10 million IoT devices with a default password "admin123" that cannot be changed. A hacker compromises millions simultaneously. What attack is this?','This is a botnet/DDoS attack — compromised IoT devices are used together to overwhelm a target server with traffic, taking it offline.',1),
(507,1,1,'mcq','S1/SS2','Internet of Things','Analyse','Hard',1,1,'An IoT health wristband continuously uploads a patient''s heart rate and location to a cloud server. What data protection issues arise?','Health and location data are sensitive personal data. Continuous collection requires explicit informed consent, secure transmission, and purpose limitation under data protection law.',1),
(508,1,1,'mcq','S1/SS2','Internet of Things','Analyse','Hard',1,1,'A city deploys IoT parking sensors across Accra. Sensors detect which spaces are occupied and display availability on an app. What systemic risk exists if the system fails?','If the central server fails, all parking information becomes unavailable simultaneously — critical city infrastructure should have redundancy and fallback systems.',1),
(509,1,1,'mcq','S1/SS2','Internet of Things','Analyse','Hard',1,1,'A smart factory uses IoT to monitor 5,000 machines. Each generates 1MB of data per minute. Calculate the data volume per day.','5,000 machines × 1MB/min × 60 min × 24 hours = 7,200,000 MB (7.2 TB) per day — requiring significant Big Data infrastructure.',1),
(510,1,1,'mcq','S1/SS2','Internet of Things','Analyse','Hard',1,1,'Ghana deploys IoT weather stations across the country to improve agricultural planning. A competing company hacks the data and sells false forecasts to farmers. What combined harms occur?','False weather data causes crop failures, economic losses, food insecurity, and destroys trust in digital agricultural systems.',1),
(511,1,1,'mcq','S1/SS2','Cloud Computing','Analyse','Hard',1,1,'A Ghanaian bank uses a foreign cloud provider. The provider''s country''s government demands access to all stored data. What legal and sovereignty issues arise?','Foreign data access laws conflict with Ghana''s banking secrecy and data protection laws. This illustrates why data residency and national cloud infrastructure matter.',1),
(512,1,1,'mcq','S1/SS2','Cloud Computing','Analyse','Hard',1,1,'A startup uses a serverless cloud architecture and their monthly bill increases 10x after a viral social media post drives unexpected traffic. Why?','Serverless billing is usage-based — viral traffic means massive unexpected usage. Cloud cost management and spending alerts are essential.',1),
(513,1,1,'mcq','S1/SS2','Cloud Computing','Analyse','Hard',1,1,'Compare the total cost of ownership (TCO) of on-premise servers versus cloud for a small Ghanaian business over 5 years.','On-premise requires high upfront hardware costs, IT staff, power, cooling, and maintenance. Cloud has lower upfront costs but ongoing subscription fees — TCO depends on scale and usage patterns.',1),
(514,1,1,'mcq','S1/SS2','Cloud Computing','Analyse','Hard',1,1,'A hospital migrates to cloud but discovers their legacy database software is incompatible with cloud infrastructure. What challenge is this?','This is a vendor lock-in and compatibility challenge — legacy systems often require significant re-engineering before cloud migration is possible.',1),
(515,1,1,'mcq','S1/SS2','Cloud Computing','Analyse','Hard',1,1,'A cloud provider guarantees 99.9% uptime in their SLA. How many hours of downtime does this allow per year?','99.9% uptime = 0.1% downtime. 0.001 × 365 × 24 = 8.76 hours of permitted downtime per year — significant for critical systems.',1),
